`include "Stump_definitions.v"

// 'include' definitions of function codes etc.
// e.g. can use "`ADD" instead of "'h0" to aid readability
// Substitute your own definitions if you prefer by
// modifying Stump_definitions.v

/*----------------------------------------------------------------------------*/

/** 
	!!! DO NOT augment the interface for the Stump_ALU module        		  !!!
	!!! Altering the interface could cause compilation and synthesis errors.  !!!
*/
module Stump_ALU (input  wire [15:0] operand_A,		// First operand
                                 input  wire [15:0] operand_B,		// Second operand
		                          input  wire [ 2:0] func,		// Function specifier
		                          input  wire        c_in,		// Carry input
		                          input  wire        csh,  		// Carry from shifter
		                          output reg  [15:0] result,		// ALU output
		                          output reg  [ 3:0] flags_out);	// Flags {N, Z, V, C}


/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -*/
/* Declarations of any internal signals and buses used                        */

reg [16:0] temporary;

/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -*/

/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -*/
/* Verilog code                                                               */

always @(*) 
begin
	result = 16'b0;
	flags_out = 4'b0;

	case(func)
		'ADD:
		begin
			temporary = {1'b0, operand_A} + {1'b0, operand_B};
			result = temporary[15:0];

			// N Flag
			flags_out[3] = result[15];

			// Z Flag
			if(result == 16'b0)
				flags_out[2] = 1;
			else
				flags_out[2] = 0;

			// V Flag
			if((operand_A[15] & operand_B[15] & ~result[15]) | (~operand_A[15] & ~operand_B[15] & result[15]))
				flags_out[1] = 1;
			else
				flags_out[1] = 0;

			// C Flag
			flags_out[0] = temporary[16];
		end

		'ADC:
		begin
			temporary = {1'b0, operand_A} + {1'b0, operand_B} + c_in;
			result = temporary[15:0];

			// N Flag
			flags_out[3] = result[15];

			// Z Flag
			if(result == 16'b0)
				flags_out[2] = 1;
			else
				flags_out[2] = 0;

			// V Flag
			if((operand_A[15] & operand_B[15] & ~result[15]) | (~operand_A[15] & ~operand_B[15] & result[15]))
				flags_out[1] = 1;
			else
				flags_out[1] = 0;

			// C Flag
			flags_out[0] = temporary[16];
		end

		'SUB:
		begin
			temporary = {1'b0, operand_A} + {1'b0, ~operand_B} + 1'b1;
			result = temporary[15:0];

			// N Flag
			flags_out[3] = result[15];

			// Z Flag
			if(result == 16'b0)
				flags_out[2] = 1;
			else
				flags_out[2] = 0;

			// V Flag
			if((operand_A[15] & ~operand_B[15] & ~result[15]) | (~operand_A[15] & operand_B[15] & result[15]))
				flags_out[1] = 1;
			else
				flags_out[1] = 0;

			// C Flag
			flags_out[0] = temporary[16];
		end

		'SBC:
		begin
			temporary = {1'b0, operand_A} + {1'b0, ~operand_B} + 1'b1 + ~c_in;
			result = temporary[15:0];

			// N Flag
			flags_out[3] = result[15];

			// Z Flag
			if(result == 16'b0)
				flags_out[2] = 1;
			else
				flags_out[2] = 0;

			// V Flag
			if((operand_A[15] & ~operand_B[15] & ~result[15]) | (~operand_A[15] & operand_B[15] & result[15]))
				flags_out[1] = 1;
			else
				flags_out[1] = 0;

			// C Flag
			flags_out[0] = temporary[16];
		end

		'AND:
		begin
			result = operand_A & operand_B;

			// N Flag
			flags_out[3] = result[15];

			// Z Flag
			if(result == 16'b0)
				flags_out[2] = 1;
			else
				flags_out[2] = 0;

			// V Flag
			flags_out[1] = 0;

			// C Flag
			flags_out[0] = csh;
		end

		'OR:
		begin
			result = operand_A | operand_B;

			// N Flag
			flags_out[3] = result[15];

			// Z Flag
			if(result == 16'b0)
				flags_out[2] = 1;
			else
				flags_out[2] = 0;

			// V Flag
			flags_out[1] = 0;

			// C Flag
			flags_out[0] = csh;
		end

		'LD, 'ST, 'BR:
		begin
			result = 16'bXXXX;
			flags_out = 4'bXXXX;
		end

		default:
		begin
			result = 16'bX;
			flags_out = 4'bX;
		end
	endcase
end

/* - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - - -*/

/*----------------------------------------------------------------------------*/

endmodule

